# ─────────────────────────────────────────────────────────────────────────────
# FrameCodec (Strategy)
# ─────────────────────────────────────────────────────────────────────────────

T = TypeVar("T")


class FrameCodec(ABC, Generic[T]):
    """Wire-format strategy: encodes outbound payloads, decodes inbound."""

    @abstractmethod
    def encode(self, payload: T) -> Union[str, bytes]:
        """Serialize an outbound payload to the wire."""

    @abstractmethod
    def decode_chunk(self, chunk: Union[str, bytes], buffer: List[T]) -> None:
        """Append decoded payloads from this chunk into ``buffer``."""


class TextFrameCodec(FrameCodec[str]):
    """PVE termproxy text framing.

    Frames:
      - ``0:LEN:PAYLOAD``: terminal data (both directions)
      - ``1:COLS:ROWS:``: resize (client→server)
      - ``2``: keepalive ping (every 30 s)

    Only ``0`` frames are surfaced to the caller.
    """

    PING_FRAME = "2"

    def __init__(self) -> None:
        self._pending = ""

    def encode(self, payload: str) -> str:
        return f"0:{len(payload)}:{payload}\n"

    @staticmethod
    def encode_resize(cols: int, rows: int) -> str:
        return f"1:{cols}:{rows}:"

    def decode_chunk(self, chunk: Union[str, bytes], buffer: List[str]) -> None:
        # PVE termproxy is asymmetric: client→server is framed
        # ``0:LEN:DATA``, server→client is the raw underlying TTY
        # output. Pass everything through verbatim.
        if isinstance(chunk, bytes):
            chunk = chunk.decode("utf-8", errors="replace")
        if chunk:
            buffer.append(chunk)
        return
        # (The original framed-decoder is preserved below for reference;
        # PVE's wire format makes it unreachable.)
        self._pending += chunk
        while True:
            colon_one = self._pending.find(":")
            if colon_one < 0:
                return
            tag = self._pending[:colon_one]
            if tag != "0":
                self._pending = self._pending[colon_one + 1:]
                continue
            colon_two = self._pending.find(":", colon_one + 1)
            if colon_two < 0:
                return
            try:
                length = int(self._pending[colon_one + 1: colon_two])
            except ValueError:
                self._pending = ""
                return
            start = colon_two + 1
            if len(self._pending) < start + length:
                return
            buffer.append(self._pending[start:start + length])
            self._pending = self._pending[start + length:]


class BinaryFrameCodec(FrameCodec[bytes]):
    """VNC: raw RFB protocol bytes pass through unchanged."""

    def encode(self, payload: bytes) -> bytes:
        return payload

    def decode_chunk(self, chunk: Union[str, bytes], buffer: List[bytes]) -> None:
        if isinstance(chunk, str):
            chunk = chunk.encode("utf-8")
        buffer.append(chunk)


