def _parse_ticket(response: Any) -> ConsoleTicket:
    """Extract ticket fields from whatever shape the typed response carries."""
    inner = getattr(response, "data", response)
    if hasattr(inner, "to_dict"):
        inner = inner.to_dict()
    if isinstance(inner, Mapping):
        return ConsoleTicket(
            ticket=str(inner["ticket"]),
            port=int(inner["port"]),
            user=str(inner.get("user", "")),
            upid=inner.get("upid"),
            cert=inner.get("cert"),
        )
    return ConsoleTicket(
        ticket=str(getattr(inner, "ticket")),
        port=int(getattr(inner, "port")),
        user=str(getattr(inner, "user", "")),
        upid=getattr(inner, "upid", None),
        cert=getattr(inner, "cert", None),
    )


# ─────────────────────────────────────────────────────────────────────────────
# AuthAttacher (Strategy) — Cookie + API-token, composable
# ─────────────────────────────────────────────────────────────────────────────


class AuthAttacher(ABC):
    @abstractmethod
    def headers(self, config: Configuration) -> Dict[str, str]: ...


class CompositeAuthAttacher(AuthAttacher):
    def __init__(self, attachers: List[AuthAttacher]) -> None:
        self._attachers = attachers

    def headers(self, config: Configuration) -> Dict[str, str]:
        merged: Dict[str, str] = {}
        for a in self._attachers:
            merged.update(a.headers(config))
        return merged


class _ApiKeyAuthAttacher(AuthAttacher):
    """Attaches the API-token `Authorization` header.

    The REST client keys api_key by the OpenAPI auth-scheme name
    (``PVEApiToken``); only the *header* it lands on is ``Authorization``.
    Look up by the scheme name so REST and WebSocket consume the same
    config — falling back to a literal ``Authorization`` slot for users
    who set the key manually.
    """

    def headers(self, config: Configuration) -> Dict[str, str]:
        api_key = (config.api_key or {})
        api_key_prefix = (config.api_key_prefix or {})
        for slot in ("PVEApiToken", "Authorization"):
            if slot in api_key:
                prefix = api_key_prefix.get(slot, "")
                value = api_key[slot]
                # PVE's `Authorization: PVEAPIToken=<id>=<secret>` has no
                # space between the prefix and the token, so join with
                # `+` rather than the OpenAPI-default `prefix + " " + value`.
                merged = f"{prefix}{value}" if prefix else value
                return {"Authorization": merged}
        return {}


class _CookieAuthAttacher(AuthAttacher):
    def headers(self, config: Configuration) -> Dict[str, str]:
        cookie = (config.api_key or {}).get("PVEAuthCookie")
        return {"Cookie": f"PVEAuthCookie={cookie}"} if cookie else {}


DEFAULT_AUTH: AuthAttacher = CompositeAuthAttacher([
    _ApiKeyAuthAttacher(),
    _CookieAuthAttacher(),
])


# ─────────────────────────────────────────────────────────────────────────────
# WebSocketTransport (Adapter) — abstracts over `websocket-client`.
# ─────────────────────────────────────────────────────────────────────────────


class WebSocketTransport(ABC):
    @abstractmethod
    def open(self, url: str, headers: Mapping[str, str], cfg: Optional[Configuration] = None) -> Any: ...


class _WebsocketClientTransport(WebSocketTransport):
    """Adapter over the optional ``websocket-client`` package.

    Reads ``cfg.verify_ssl`` so the WebSocket leg honors the same TLS
    posture as the REST client — without this, a self-signed PVE host
    would let the REST calls through (urllib3 sees ``verify_ssl=False``)
    but trip on the WS handshake.
    """

    def open(self, url: str, headers: Mapping[str, str], cfg: Optional[Configuration] = None) -> Any:
        try:
            from websocket import create_connection  # type: ignore[import-not-found]
        except ImportError as exc:
            raise ImportError(
                "WebSocket support requires the optional `websocket-client` package. "
                "Install with: pip install websocket-client"
            ) from exc
        header_list = [f"{k}: {v}" for k, v in headers.items()]
        sslopt: Dict[str, Any] = {}
        if cfg is not None and not getattr(cfg, "verify_ssl", True):
            import ssl as _ssl
            sslopt["cert_reqs"] = _ssl.CERT_NONE
            sslopt["check_hostname"] = False
        return create_connection(url, header=header_list, sslopt=sslopt or None)


DEFAULT_TRANSPORT: WebSocketTransport = _WebsocketClientTransport()


# ─────────────────────────────────────────────────────────────────────────────
# UrlBuilder
# ─────────────────────────────────────────────────────────────────────────────


class UpgradeUrlBuilder:
    @staticmethod
    def build(config: Configuration, base_path: str, ticket: ConsoleTicket) -> str:
        parsed = urlparse(config.host)
        scheme = "wss" if parsed.scheme == "https" else "ws"
        ws_base = urlunparse(parsed._replace(scheme=scheme))
        return (
            f"{ws_base.rstrip('/')}{base_path}/vncwebsocket"
            f"?port={ticket.port}&vncticket={quote(ticket.ticket, safe='')}"
        )


# ─────────────────────────────────────────────────────────────────────────────
# Sessions — delegate framing to the codec, own lifecycle (heartbeat)
# ─────────────────────────────────────────────────────────────────────────────


PING_INTERVAL_S = 30


class _BaseSession:
    def __init__(self, ws: Any) -> None:
        self._ws = ws
        self._closed = False

    def close(self) -> None:
        if self._closed:
            return
        self._closed = True
        try:
            self._ws.close()
        except Exception:  # noqa: BLE001
            pass


class TerminalSession(_BaseSession):
    """Active terminal session over the upgraded WebSocket."""

    def __init__(
        self,
        ws: Any,
        on_message: Optional[Callable[[str], None]] = None,
        on_close: Optional[Callable[[int, str], None]] = None,
        on_error: Optional[Callable[[Exception], None]] = None,
    ) -> None:
        super().__init__(ws)
        self._codec = TextFrameCodec()
        self._on_message = on_message
        self._on_close = on_close
        self._on_error = on_error
        self._reader = threading.Thread(target=self._read_loop, name="pve-terminal-reader", daemon=True)
        self._pinger = threading.Thread(target=self._ping_loop, name="pve-terminal-pinger", daemon=True)
        self._reader.start()
        self._pinger.start()

    def send(self, text: str) -> None:
        self._ws.send(self._codec.encode(text))

    def resize(self, cols: int, rows: int) -> None:
        self._ws.send(TextFrameCodec.encode_resize(cols, rows))

    def _read_loop(self) -> None:
        decoded: List[str] = []
        try:
            while not self._closed:
                frame = self._ws.recv()
                if frame is None or frame == "":
                    break
                self._codec.decode_chunk(frame, decoded)
                while decoded:
                    msg = decoded.pop(0)
                    if self._on_message:
                        self._on_message(msg)
        except Exception as exc:  # noqa: BLE001
            if self._on_error and not self._closed:
                self._on_error(exc)
        finally:
            self._closed = True
            if self._on_close:
                self._on_close(1000, "stream ended")

    def _ping_loop(self) -> None:
        while not self._closed:
            time.sleep(PING_INTERVAL_S)
            if self._closed:
                return
            try:
                self._ws.send(TextFrameCodec.PING_FRAME)
            except Exception:  # noqa: BLE001
                self._closed = True
                return


class VncSession(_BaseSession):
    """Active VNC session over the upgraded WebSocket. Frames are raw RFB."""

    def __init__(
        self,
        ws: Any,
        on_frame: Optional[Callable[[bytes], None]] = None,
        on_close: Optional[Callable[[int, str], None]] = None,
        on_error: Optional[Callable[[Exception], None]] = None,
    ) -> None:
        super().__init__(ws)
        self._codec = BinaryFrameCodec()
        self._on_frame = on_frame
        self._on_close = on_close
        self._on_error = on_error
        self._reader = threading.Thread(target=self._read_loop, name="pve-vnc-reader", daemon=True)
        self._reader.start()

    def send(self, data: bytes) -> None:
        self._ws.send_binary(self._codec.encode(data))

    def _read_loop(self) -> None:
        decoded: List[bytes] = []
        try:
            while not self._closed:
                frame = self._ws.recv()
                if frame is None or frame == b"" or frame == "":
                    break
                self._codec.decode_chunk(frame, decoded)
                while decoded:
                    if self._on_frame:
                        self._on_frame(decoded.pop(0))
                    else:
                        decoded.pop(0)
        except Exception as exc:  # noqa: BLE001
            if self._on_error and not self._closed:
                self._on_error(exc)
        finally:
            self._closed = True
            if self._on_close:
                self._on_close(1000, "stream ended")


# ─────────────────────────────────────────────────────────────────────────────
# ConsoleConnector (Template Method)
# ─────────────────────────────────────────────────────────────────────────────


SessionT = TypeVar("SessionT")


class ConsoleConnector(Generic[TargetT, SessionT]):
    """Orchestrates the four-step pipeline. Strategies vary the *what*."""

    def __init__(
        self,
        registry: Mapping[type, TicketIssuer],
        session_factory: Callable[[Any, Any], SessionT],
        auth: AuthAttacher = DEFAULT_AUTH,
        transport: WebSocketTransport = DEFAULT_TRANSPORT,
        needs_inband_auth: bool = False,
    ) -> None:
        self._registry = registry
        self._session_factory = session_factory
        self._auth = auth
        self._transport = transport
        self._needs_inband_auth = needs_inband_auth

    def connect(self, config: Configuration, target: TargetT, callbacks: Any) -> SessionT:
        client = ApiClient(configuration=config)
        issuer = self._registry.get(type(target))
        if issuer is None:
            raise TypeError(f"no issuer registered for target type {type(target).__name__}")
        issued = issuer.issue(client, target)
        url = UpgradeUrlBuilder.build(config, issued.base_path, issued.ticket)
        socket = self._transport.open(url, self._auth.headers(config), config)
        # PVE termproxy expects ``<user>:<vncticket>\n`` as the very
        # first frame after the WS handshake. ``websocket-client``'s
        # ``create_connection`` returns once the upgrade is complete,
        # so the socket is already open here — push the auth inline.
        if self._needs_inband_auth:
            socket.send(f"{issued.ticket.user}:{issued.ticket.ticket}\n")
        return self._session_factory(socket, callbacks)


def _make_terminal_session(socket: Any, callbacks: Mapping[str, Optional[Callable]]) -> TerminalSession:
    return TerminalSession(
        socket,
        on_message=callbacks.get("on_message"),
        on_close=callbacks.get("on_close"),
        on_error=callbacks.get("on_error"),
    )


def _make_vnc_session(socket: Any, callbacks: Mapping[str, Optional[Callable]]) -> VncSession:
    return VncSession(
        socket,
        on_frame=callbacks.get("on_frame"),
        on_close=callbacks.get("on_close"),
        on_error=callbacks.get("on_error"),
    )


_TERMINAL_CONNECTOR: ConsoleConnector[TerminalTarget, TerminalSession] = ConsoleConnector(
    TERMINAL_ISSUERS, _make_terminal_session, needs_inband_auth=True,
)

_VNC_CONNECTOR: ConsoleConnector[VncTarget, VncSession] = ConsoleConnector(
    VNC_ISSUERS, _make_vnc_session,
)


# ─────────────────────────────────────────────────────────────────────────────
# Public API
# ─────────────────────────────────────────────────────────────────────────────


def connect_terminal(
    config: Configuration,
    target: TerminalTarget,
    on_message: Optional[Callable[[str], None]] = None,
    on_close: Optional[Callable[[int, str], None]] = None,
    on_error: Optional[Callable[[Exception], None]] = None,
) -> TerminalSession:
    """Open a terminal session against a node, QEMU VM, or LXC container."""
    return _TERMINAL_CONNECTOR.connect(
        config, target,
        {"on_message": on_message, "on_close": on_close, "on_error": on_error},
    )


def connect_vnc(
    config: Configuration,
    target: VncTarget,
    on_frame: Optional[Callable[[bytes], None]] = None,
    on_close: Optional[Callable[[int, str], None]] = None,
    on_error: Optional[Callable[[Exception], None]] = None,
) -> VncSession:
    """Open a VNC session against a node shell, QEMU VM, or LXC container."""
    return _VNC_CONNECTOR.connect(
        config, target,
        {"on_frame": on_frame, "on_close": on_close, "on_error": on_error},
    )
